/* ============================================================
   allergene-bersicht — Einleitung + Erklär-Animation (Zutat->Rezept->Gericht)
   Ein Allergen wird EINMAL an der Zutat gepflegt und erbt sich
   automatisch ins Rezept und ins Gericht. Linearer Fluss, Pfeile
   sitzen in den Lücken zwischen den Karten (ragen nie hinein).
   Champagner-Gold, Glas-Karten, Lineal TS. Full-Width, mittig.
   Kein neuer Font/keine neue Farbe.
   ============================================================ */
(function(){
  if(window.__tsalg) return; window.__tsalg=true;
  var GOLD='199,180,137';
  var SANS='-apple-system,BlinkMacSystemFont,"SF Pro Display","Helvetica Neue",sans-serif';
  function on(){ return /\/allergene-bersicht\/?$/.test(location.pathname); }

  var CSS = `
  #tsalg{width:100vw;max-width:100vw;margin:20px 0 60px;margin-left:calc(50% - 50vw);font-family:${SANS};color:#fff}
  #tsalg *{box-sizing:border-box}
  #tsalg .tsalg-inner{width:min(1040px,92vw);margin:0 auto}
  #tsalg .tsalg-lead{max-width:820px;margin:0 auto 34px;text-align:center}
  #tsalg .tsalg-lead p{margin:0 0 14px;font-size:1.05rem;line-height:1.65;color:#e6e6e6}
  #tsalg .tsalg-lead p:last-child{margin-bottom:0}

  #tsalg .tsalg-stage{display:flex;align-items:center;justify-content:center;flex-wrap:nowrap;max-width:1000px;margin:0 auto}
  #tsalg .tsalg-card{flex:1 1 0;min-width:0;max-width:250px;
    background:linear-gradient(180deg,rgba(255,255,255,.05),rgba(255,255,255,.02));
    border:1px solid rgba(255,255,255,.1);border-radius:16px;padding:0;overflow:hidden;
    box-shadow:0 22px 50px -32px rgba(0,0,0,.9);opacity:0;transform:translateY(12px);
    transition:opacity .5s ease,transform .5s cubic-bezier(.16,1,.3,1),border-color .4s ease,box-shadow .5s ease}
  #tsalg .tsalg-card.in{opacity:1;transform:none}
  #tsalg .tsalg-card.lit{border-color:rgba(${GOLD},.42);box-shadow:0 0 0 1px rgba(${GOLD},.18),0 22px 50px -30px rgba(0,0,0,.9),0 0 34px -8px rgba(${GOLD},.4)}
  #tsalg .tc-img{width:100%;aspect-ratio:16/10;background:#000;overflow:hidden;position:relative}
  #tsalg .tc-img::after{content:"";position:absolute;inset:0;background:linear-gradient(180deg,rgba(4,5,10,0) 55%,rgba(6,7,13,.85) 100%)}
  #tsalg .tc-img img{width:100%;height:100%;object-fit:cover;display:block;transform:scale(1.04);transition:transform .6s cubic-bezier(.16,1,.3,1)}
  #tsalg .tsalg-card.lit .tc-img img{transform:scale(1)}
  #tsalg .tc-body{padding:14px 15px 16px}
  #tsalg .tc-type{font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:#c7b489;margin:0 0 7px}
  #tsalg .tc-name{font-family:"Lineal TS", var(--font-sans, ${SANS});font-weight:600;font-size:1.06rem;line-height:1.15;margin:0 0 12px;color:#fff}
  #tsalg .tc-badge{display:inline-flex;align-items:center;gap:7px;padding:5px 10px 5px 8px;border-radius:999px;
    background:rgba(${GOLD},.12);border:1px solid rgba(${GOLD},.4);color:#ece1c7;font-size:12.5px;font-weight:600;
    opacity:0;transform:translateY(6px) scale(.9);transition:opacity .45s ease,transform .45s cubic-bezier(.16,1,.3,1)}
  #tsalg .tc-badge svg{width:14px;height:14px;flex:none;stroke:#c7b489}
  #tsalg .tc-badge.show{opacity:1;transform:none}
  #tsalg .tc-tag{display:block;margin-top:9px;font-size:10.5px;letter-spacing:.14em;text-transform:uppercase;
    color:rgba(${GOLD},.85);opacity:0;transition:opacity .4s ease .1s}
  #tsalg .tc-tag.src{color:rgba(255,255,255,.4)}
  #tsalg .tc-tag.show{opacity:1}

  /* Connector in der Lücke (Pfeil ragt nie in die Karten) */
  #tsalg .tsalg-conn{flex:0 0 clamp(38px,5vw,82px);align-self:center;position:relative;height:14px;margin:0 6px}
  #tsalg .tsalg-conn .ln{position:absolute;left:0;top:6px;height:2px;width:calc(100% - 7px);transform:scaleX(0);transform-origin:left;
    background:linear-gradient(90deg,rgba(${GOLD},.18),rgba(${GOLD},.7));border-radius:2px;
    transition:transform .7s cubic-bezier(.16,1,.3,1);filter:drop-shadow(0 0 5px rgba(${GOLD},.3))}
  #tsalg .tsalg-conn .hd{position:absolute;right:0;top:2px;width:0;height:0;
    border-left:8px solid rgba(${GOLD},.9);border-top:5px solid transparent;border-bottom:5px solid transparent;
    opacity:0;transform:scale(.4);transform-origin:right center;transition:opacity .3s ease,transform .3s cubic-bezier(.34,1.56,.64,1)}
  #tsalg .tsalg-conn.on .ln{transform:scaleX(1)}
  #tsalg .tsalg-conn.on .hd{opacity:1;transform:scale(1);transition-delay:.48s}

  #tsalg .tsalg-cap{max-width:640px;margin:34px auto 0;text-align:center;font-size:16px;line-height:1.6;color:#fff}
  #tsalg .tsalg-cap b{color:#c7b489;font-weight:600}

  /* Mobile: vertikaler Stapel, Pfeil zeigt nach unten */
  @media (max-width:760px){
    #tsalg .tsalg-stage{flex-direction:column;max-width:340px}
    #tsalg .tsalg-card{width:100%;max-width:none;flex:0 0 auto}
    #tsalg .tsalg-conn{flex-basis:auto;width:14px;height:30px;margin:2px 0}
    #tsalg .tsalg-conn .ln{left:6px;top:0;width:2px;height:calc(100% - 6px);transform:scaleY(0);transform-origin:top}
    #tsalg .tsalg-conn.on .ln{transform:scaleY(1)}
    #tsalg .tsalg-conn .hd{right:auto;left:1px;top:auto;bottom:0;
      border-left:5px solid transparent;border-right:5px solid transparent;border-top:8px solid rgba(${GOLD},.9);
      border-bottom:0;transform-origin:center bottom}
  }
  @media (prefers-reduced-motion:reduce){ #tsalg *{transition:none!important;animation:none!important} }`;

  var WHEAT = '<svg viewBox="0 0 24 24" fill="none" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22V8"/><path d="M12 8c0-2 1.5-3.5 3.5-3.5C15.5 6.5 14 8 12 8Z"/><path d="M12 8c0-2-1.5-3.5-3.5-3.5C8.5 6.5 10 8 12 8Z"/><path d="M12 14c0-2 1.5-3.5 3.5-3.5C15.5 12.5 14 14 12 14Z"/><path d="M12 14c0-2-1.5-3.5-3.5-3.5C8.5 12.5 10 14 12 14Z"/></svg>';

  function badge(tag, tagCls){
    return '<span class="tc-badge">'+WHEAT+'Gluten</span>'+
           '<span class="tc-tag '+(tagCls||'')+'">'+tag+'</span>';
  }
  function conn(){ return '<div class="tsalg-conn"><span class="ln"></span><span class="hd"></span></div>'; }

  var IMG={
    mehl:"https://files.catbox.moe/rdk2ux.png",
    teig:"https://files.catbox.moe/wn29tf.png",
    pizza:"https://files.catbox.moe/0uk9xg.png"
  };
  (function(){ for(var k in IMG){ var p=new Image(); p.src=IMG[k]; } })();
  function card(n, img, alt, type, name, tag, tagCls){
    return '<div class="tsalg-card" data-n="'+n+'">'+
      '<div class="tc-img"><img src="'+img+'" alt="'+alt+'" loading="eager"></div>'+
      '<div class="tc-body"><p class="tc-type">'+type+'</p><p class="tc-name">'+name+'</p>'+badge(tag,tagCls)+'</div>'+
    '</div>';
  }

  function build(){
    var sec=document.createElement('section');
    sec.id='tsalg';
    sec.innerHTML =
      '<div class="tsalg-inner">'+
        '<div class="tsalg-lead">'+
          '<p>Allergene und Verpackungen sauber zu dokumentieren ist Pflicht, und in den meisten Betrieben läuft es von Hand. Dieselbe Angabe trägst du an jeder Stelle neu ein, in der Karte wie auf dem Etikett. Ändert sich eine Zutat, ziehst du alles einzeln nach. Genau da passieren die Fehler.</p>'+
          '<p>Zwei Datenbanken drehen das um. Ein Allergen pflegst du einmal an der Zutat, die Verpackung einmal am Gericht. Von dort erbt sich beides automatisch dorthin, wo es gebraucht wird. Du pflegst die Quelle, Kennzeichnung und Verpackungsangaben schreiben sich selbst.</p>'+
        '</div>'+
        '<div class="tsalg-stage">'+
          card('a', IMG.mehl, 'Weizenmehl', 'Zutat', 'Weizenmehl', 'einmal gepflegt', 'src')+
          conn()+
          card('b', IMG.teig, 'Pizzateig', 'Rezept', 'Pizzateig', 'automatisch')+
          conn()+
          card('c', IMG.pizza, 'Pizza Margherita', 'Gericht', 'Pizza Margherita', 'automatisch')+
        '</div>'+
        '<p class="tsalg-cap">Ein Eintrag an der Quelle, <b>überall korrekt gekennzeichnet</b>.</p>'+
      '</div>';
    return sec;
  }

  function play(sec){
    var reduce = window.matchMedia && window.matchMedia('(prefers-reduced-motion:reduce)').matches;
    var cards={a:sec.querySelector('[data-n="a"]'),b:sec.querySelector('[data-n="b"]'),c:sec.querySelector('[data-n="c"]')};
    var conns=sec.querySelectorAll('.tsalg-conn');
    function badgeOn(card){ var b=card.querySelector('.tc-badge'),t=card.querySelector('.tc-tag'); if(b)b.classList.add('show'); if(t)t.classList.add('show'); }

    if(reduce){
      Object.keys(cards).forEach(function(k){ cards[k].classList.add('in','lit'); badgeOn(cards[k]); });
      conns.forEach(function(c){ c.classList.add('on'); }); return;
    }
    // Quelle
    cards.a.classList.add('in','lit'); badgeOn(cards.a);
    if(conns[0]) setTimeout(function(){ conns[0].classList.add('on'); }, 350);
    // -> Rezept
    setTimeout(function(){ cards.b.classList.add('in'); }, 750);
    setTimeout(function(){ cards.b.classList.add('lit'); badgeOn(cards.b); }, 1200);
    if(conns[1]) setTimeout(function(){ conns[1].classList.add('on'); }, 1550);
    // -> Gericht
    setTimeout(function(){ cards.c.classList.add('in'); }, 1950);
    setTimeout(function(){ cards.c.classList.add('lit'); badgeOn(cards.c); }, 2400);
  }

  function mount(){
    if(!on()) return;
    var sc=document.querySelector('.super-content'); if(!sc) return;
    if(document.getElementById('tsalg')) return;
    var hero=sc.querySelector('.ts-hero'), nr=sc.querySelector('.notion-root');
    if(!hero && !nr) return;
    if(!document.getElementById('tsalg-css')){ var st=document.createElement('style'); st.id='tsalg-css'; st.textContent=CSS; document.head.appendChild(st); }
    var sec=build();
    if(hero && hero.nextSibling){ hero.parentNode.insertBefore(sec, hero.nextSibling); }
    else if(nr){ nr.parentNode.insertBefore(sec, nr); }
    else sc.appendChild(sec);

    var done=false; function go(){ if(done) return; done=true; play(sec); }
    try{ var io=new IntersectionObserver(function(es){ es.forEach(function(e){ if(e.isIntersecting && e.intersectionRatio>0.18) go(); }); },{threshold:[0,.18,.4]}); io.observe(sec); }catch(e){}
    var tries=0; (function poll(){ if(done) return; var r=sec.getBoundingClientRect(); if(r.top < window.innerHeight*0.85 && r.bottom>0){ go(); return; } if(tries++<40) setTimeout(poll,250); })();
  }

  mount();
  document.addEventListener('DOMContentLoaded', mount);
  new MutationObserver(mount).observe(document.documentElement,{childList:true,subtree:true});
})();

