/* ============================================================
   gemeinkosten-mitarbeiterlhne — #tsgkflow  "Von den Kosten zum
   Deckungsbeitrag" (Robert-Wunsch 17.07.2026, direkt unter #tsgkemp).
   v2 (selber Tag, "luxuriöser eleganter und mit Bildern"): von reinen
   Text-Pills auf fotografische Medaillon-Knoten umgebaut — jedes
   Kettenglied bekommt ein rundes Foto aus der bereits bestehenden
   Tasty-Studios-Bildbibliothek (img/gemeinkosten/, img/mitarbeiterloehne/,
   SSOT-Wiederverwendung: "GK pro Produkt" nutzt exakt dasselbe Bild
   (telefon.jpg), das im Warenkorb DB VI-Annahmen bereits für das
   Feld "GK / Produkt" steht). EINE Glaskarte (Sprache wie #tsgkemp),
   Gold-Ring um jedes Medaillon, Verbindungslinien mit Shimmer-Sweep
   (Muster wie .tss-bar__fill::after), Ergebnis-Badges größer + Glow.
   Zwei Rechenketten, EIN Abschnitt: GK-Kette zuerst (Gemeinkosten →
   Gemeinkostenannahmen → GK pro Produkt → = Deckungsbeitrag II),
   danach PK-Kette (Mitarbeiterlöhne × AG-Faktor → Lohn pro Stunde →
   Zubereitungszeit pro Minute → PK pro Produkt → = Deckungsbeitrag III).
   Mapping bestätigt gegen die SSOT-Treppe #tsdb (mehrwert-zielbild,
   von Robert bestätigt 2026-07-10): DB II = DB I − Gemeinkostenanteil,
   DB III = DB II − Personalkostenanteil → GK-Kette produziert DB II,
   PK-Kette DB III. Reveal-Reihenfolge zeigt daher GK/DB II ZUERST,
   PK/DB III DANACH — deckt sich mit "dreh es um: erst DB II dann DB III".
   Reiner Konzept-Flow (Ketten/Formeln), KEINE erfundenen Euro-Beträge
   (Niemals-schätzen-Regel). Anker: direkt NACH #tsgkemp.
   ============================================================ */
(function(){
  if(window.__tsgkflow) return; window.__tsgkflow=true;
  var PATH=/\/gemeinkosten-mitarbeiterlhne\/?$/;
  var GK_IMG='https://tastyrob123.github.io/kurs/img/gemeinkosten/';
  var MA_IMG='https://tastyrob123.github.io/kurs/img/mitarbeiterloehne/';
  /* op/cap = Operator-Symbol + Mini-Erklaerung fuer die Verbindung VOR diesem Knoten
     (Robert-Feedback 17.07.2026: "striche zu symbolen die erklaeren was wie zusammenhaengt").
     Liest sich als Gleichung: Gemeinkosten Σ/Monat → ÷ je Stueck → GK pro Produkt → − von DB I → DB II. */
  var GK_CHAIN=[
    {t:'Gemeinkosten',            img:GK_IMG+'miete-schluessel.jpg',    sub:'Miete, Strom, Versicherungen & Co.'},
    {t:'Gemeinkostenannahmen',    img:GK_IMG+'buchhaltung-rechner.jpg', op:'Σ', cap:'werden monatlich addiert', sub:'Alle Gemeinkosten eines Monats'},
    {t:'GK pro Produkt',          img:GK_IMG+'telefon.jpg',             op:'÷', cap:'geteilt durch verkaufte Stückzahl', sub:'Gemeinkostenanteil je verkauftem Produkt'},
    {t:'Deckungsbeitrag II',      img:MA_IMG+'trinkgeldglas.jpg',       op:'→', cap:'wird von DB I abgezogen', sub:'DB I − GK pro Produkt', result:true}
  ];
  var PK_CHAIN=[
    {t:'Mitarbeiterlöhne × AG-Faktor', img:MA_IMG+'lohnumschlag.jpg',                                        sub:'Bruttolöhne plus Arbeitgeberanteil'},
    {t:'Lohn pro Stunde',              img:MA_IMG+'zeiterfassungsterminal.jpg', op:'÷', cap:'geteilt durch Arbeitsstunden',       sub:'Personalkosten je Arbeitsstunde'},
    {t:'Zubereitungszeit pro Minute',  img:MA_IMG+'dienstplan.jpg',             op:'×', cap:'mal Zubereitungszeit',               sub:'Zeit, die ein Produkt in der Zubereitung braucht'},
    {t:'PK pro Produkt',               img:MA_IMG+'kochjacke.jpg',              op:'=', cap:'ergibt den Personalkostenanteil',    sub:'Personalkostenanteil je verkauftem Produkt'},
    {t:'Deckungsbeitrag III',          img:MA_IMG+'kellnerbrieftasche.jpg',     op:'→', cap:'wird von DB II abgezogen',           sub:'DB II − PK pro Produkt', result:true}
  ];
  var CSS=`
  #tsgkflow{--g:199,180,137;width:100vw;margin-left:calc(50% - 50vw);margin-right:calc(50% - 50vw);margin-top:56px;margin-bottom:60px;padding-left:clamp(20px,5vw,80px);padding-right:clamp(20px,5vw,80px);position:relative;font-family:-apple-system,BlinkMacSystemFont,"SF Pro Display","Helvetica Neue",sans-serif;color:#fff;text-align:center;opacity:0;transform:translateY(24px);transition:opacity .9s cubic-bezier(.16,1,.3,1),transform .9s cubic-bezier(.16,1,.3,1)}
  #tsgkflow.in{opacity:1;transform:none}
  #tsgkflow *{box-sizing:border-box}
  #tsgkflow .hd{font-family:"Lineal TS",-apple-system,BlinkMacSystemFont,"SF Pro Display",sans-serif;font-size:clamp(1.55rem,2.7vw,2.05rem);font-weight:600;letter-spacing:-.015em;line-height:1.15;margin:0 0 10px}
  #tsgkflow .hd .g{color:#c7b489}
  #tsgkflow .sub{font-size:.98rem;line-height:1.62;color:rgba(255,255,255,.86);max-width:54ch;margin:0 auto 46px}
  #tsgkflow .row{margin-bottom:44px}
  #tsgkflow .row:last-child{margin-bottom:0}
  #tsgkflow .row+.row{padding-top:44px;position:relative}
  #tsgkflow .row+.row::before{content:"";position:absolute;top:0;left:14%;right:14%;height:1px;background:linear-gradient(90deg,transparent,rgba(255,255,255,.10),transparent)}
  #tsgkflow .row-lbl{display:block;font-family:"Lineal TS",-apple-system,BlinkMacSystemFont,"SF Pro Display",sans-serif;font-size:clamp(1.3rem,2.1vw,1.7rem);font-weight:600;letter-spacing:-.01em;color:#fff;text-align:center;margin-bottom:30px;opacity:0;transform:translateY(8px);transition:opacity .6s ease,transform .6s ease}
  #tsgkflow.in .row-lbl{opacity:1;transform:none}
  #tsgkflow .row-lbl .g{color:#c7b489}
  #tsgkflow .chain{display:flex;flex-wrap:wrap;align-items:flex-start;justify-content:center;gap:0}
  #tsgkflow .node{display:flex;flex-direction:column;align-items:center;width:118px;opacity:0;filter:blur(6px);transform:translateY(16px) scale(.94);transition:opacity .7s cubic-bezier(.16,1,.3,1),transform .7s cubic-bezier(.16,1,.3,1),filter .7s cubic-bezier(.16,1,.3,1);transition-delay:calc(var(--i) * 180ms)}
  #tsgkflow.in .node{opacity:1;filter:blur(0);transform:none}
  /* Feste 150px-Medaillon-Zone -> ALLE Bubbles (klein wie gross) auf EINER Mittellinie (75px)
     zentriert, Labels darunter auf gemeinsamer Grundlinie (Robert 17.07.2026: "alles mittig, elegant"). */
  #tsgkflow .node-box{width:100%;height:150px;display:flex;align-items:center;justify-content:center}
  #tsgkflow .node-med{position:relative;width:78px;height:78px;border-radius:50%;overflow:hidden;box-shadow:0 10px 26px -10px rgba(0,0,0,.7),0 0 0 1px rgba(255,255,255,.08),0 0 0 4px rgba(var(--g),.14)}
  #tsgkflow .node-med img{width:100%;height:100%;object-fit:cover;display:block}
  #tsgkflow .node-lbl{margin-top:14px;font-size:.78rem;font-weight:600;line-height:1.35;color:rgba(255,255,255,.62);max-width:118px}
  /* Ergebnis-Knoten (Deckungsbeitrag II/III) deutlich groesser + staerker leuchtend (Robert 17.07.2026) */
  #tsgkflow .node.result{width:190px}
  #tsgkflow .node.result .node-med{width:150px;height:150px;box-shadow:0 20px 46px -14px rgba(0,0,0,.8),0 0 0 1px rgba(255,255,255,.12),0 0 0 6px rgba(var(--g),.5),0 0 46px rgba(var(--g),.4);animation:tsgkflow-glow 3.4s ease-in-out infinite}
  #tsgkflow .node.result .node-lbl{margin-top:14px;font-family:"Lineal TS",-apple-system,BlinkMacSystemFont,"SF Pro Display",sans-serif;font-size:1.12rem;font-weight:600;letter-spacing:-.01em;color:#efe6d2;max-width:190px}
  #tsgkflow .node-sub{margin-top:7px;font-size:.72rem;font-weight:500;line-height:1.32;letter-spacing:.01em;color:rgba(199,180,137,.85);max-width:116px}
  #tsgkflow .node.result .node-sub{max-width:200px}
  @keyframes tsgkflow-glow{0%,100%{box-shadow:0 20px 46px -14px rgba(0,0,0,.8),0 0 0 1px rgba(255,255,255,.12),0 0 0 6px rgba(var(--g),.5),0 0 46px rgba(var(--g),.4)}50%{box-shadow:0 20px 52px -12px rgba(0,0,0,.8),0 0 0 1px rgba(255,255,255,.14),0 0 0 6px rgba(var(--g),.7),0 0 62px rgba(var(--g),.6)}}
  /* Verbindung = Operator-Chip (absolut auf der Medaillon-Mittellinie 75px zentriert) + Caption darunter */
  #tsgkflow .link{position:relative;width:clamp(92px,10vw,140px);height:150px;flex:0 0 auto}
  #tsgkflow .link-op{position:absolute;top:52px;left:50%;margin-left:-19px;width:38px;height:38px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:1.2rem;font-weight:600;line-height:1;color:#efe6d2;background:radial-gradient(circle at 50% 35%,rgba(var(--g),.28),rgba(var(--g),.08));border:1px solid rgba(var(--g),.55);box-shadow:0 6px 18px -8px rgba(0,0,0,.7),0 0 16px rgba(var(--g),.22);opacity:0;transform:scale(.5);transition:opacity .5s ease,transform .55s cubic-bezier(.22,1,.36,1);transition-delay:calc(var(--i) * 180ms)}
  #tsgkflow.in .link-op{opacity:1;transform:none}
  #tsgkflow .link-cap{position:absolute;top:96px;left:-8px;right:-8px;text-align:center;font-size:.72rem;font-weight:500;letter-spacing:.01em;line-height:1.28;color:rgba(255,255,255,.58);white-space:normal;opacity:0;transform:translateY(4px);transition:opacity .5s ease,transform .5s ease;transition-delay:calc(var(--i) * 180ms + 130ms)}
  #tsgkflow.in .link-cap{opacity:1;transform:none}
  @media(max-width:760px){#tsgkflow .chain{gap:16px 8px}#tsgkflow .node{width:120px}#tsgkflow .node-box{height:auto}#tsgkflow .node-med{width:72px;height:72px}#tsgkflow .node.result{width:150px}#tsgkflow .node.result .node-med{width:120px;height:120px}#tsgkflow .link{width:100%;flex:0 0 100%;height:auto;display:flex;flex-direction:row;justify-content:center;align-items:center;gap:10px}#tsgkflow .link-op{position:static;margin:0}#tsgkflow .link-cap{position:static}#tsgkflow .hd{font-size:1.4rem}}
  @media(prefers-reduced-motion:reduce){#tsgkflow,#tsgkflow.in{opacity:1;transform:none;transition:none}#tsgkflow .node,#tsgkflow .link-op,#tsgkflow .link-cap,#tsgkflow .row-lbl{opacity:1;filter:none;transform:none;transition:none}#tsgkflow .node.result .node-med{animation:none}}
  `;
  function on(){ return PATH.test(location.pathname); }
  function injectCSS(){ if(document.getElementById('tsgkflow-css'))return; var s=document.createElement('style'); s.id='tsgkflow-css'; s.textContent=CSS; document.head.appendChild(s); }
  /* "Deckungsbeitrag II/III" ist ein GANZ NORMALER Kettenglied-Knoten am Ende
     der jeweiligen Kette (Foto + Label, .result nur fuer den Gold-Ring) —
     KEIN separates Pill/Badge-Element mehr. Robert-Feedback 17.07.2026:
     das Pill brach in 3 Zeilen um ("=" / "Deckungsbeitrag" / "II" wirkte wie
     falsche Gleichzeichen) UND hing unter der Zeile statt darin — beides
     durch "ist einfach der letzte Knoten der Kette" strukturell erledigt. */
  function chain(items, startIdx){
    var out='', i=startIdx;
    items.forEach(function(it, idx){
      if(idx>0){
        out+='<div class="link" style="--i:'+i+'"><span class="link-op">'+(it.op||'→')+'</span>'
          +(it.cap?'<span class="link-cap">'+it.cap+'</span>':'')+'</div>';
        i++;
      }
      out += '<div class="node'+(it.result?' result':'')+'" style="--i:'+i+'">'
        +'<div class="node-box"><div class="node-med"><img src="'+it.img+'" alt="'+it.t+'" loading="lazy" decoding="async"></div></div>'
        +'<div class="node-lbl">'+it.t+'</div>'
        +(it.sub?'<div class="node-sub">'+it.sub+'</div>':'')+'</div>';
      i++;
    });
    return {html:out, next:i};
  }
  function build(){
    var root=document.createElement('div'); root.id='tsgkflow';
    var i=0;
    var gk=chain(GK_CHAIN, i); i=gk.next;
    var pk=chain(PK_CHAIN, i); i=pk.next;
    root.innerHTML=
      '<div class="hd">Von den Kosten zum <span class="g">Deckungsbeitrag</span></div>'+
      '<p class="sub">Zwei Rechenketten, ein Ziel — so verdichten sich deine Kosten Schritt für Schritt zu Deckungsbeitrag II und III.</p>'+
      '<div class="row row-gk">'+
        '<span class="row-lbl">Gemein<span class="g">kosten</span></span>'+
        '<div class="chain">'+gk.html+'</div>'+
      '</div>'+
      '<div class="row row-pk">'+
        '<span class="row-lbl">Personal<span class="g">kosten</span></span>'+
        '<div class="chain">'+pk.html+'</div>'+
      '</div>';
    return root;
  }
  function mount(){
    if(!on()){ var e=document.getElementById('tsgkflow'); if(e&&e.parentNode)e.parentNode.removeChild(e); return; }
    var anchor=document.getElementById('tsgkemp'); if(!anchor) return;
    if(document.getElementById('tsgkflow')) return;
    injectCSS();
    var root=build();
    anchor.parentNode.insertBefore(root, anchor.nextSibling);
    var io=new IntersectionObserver(function(e){
      if(e[0].isIntersecting){ root.classList.add('in'); io.disconnect(); }
    },{threshold:.2});
    io.observe(root);
  }
  function boot(){
    var tries=0;
    var iv=setInterval(function(){ tries++; mount(); if(tries>60) clearInterval(iv); },300);
    new MutationObserver(function(){ if(on()) mount(); }).observe(document.documentElement,{childList:true,subtree:true});
  }
  if(document.readyState==='complete') boot(); else window.addEventListener('load',boot);
})();


